window.PPL_DATA = {"sources": {"BOOK": {"label": "BOOK VERIFIED", "tone": "green", "title_ro": "Pooley’s Air Pilot’s Manual Vol. 1", "title_en": "Pooley’s Air Pilot’s Manual Vol. 1", "text_ro": "Rezumat original verificat față de exercițiul și intervalul de pagini din manualul încărcat.", "text_en": "Original summary checked against the exercise and page range in the uploaded manual."}, "EASA": {"label": "EASA SYLLABUS", "tone": "blue", "title_ro": "EASA Part-FCL / AMC1 FCL.210 PPL(A)", "title_en": "EASA Part-FCL / AMC1 FCL.210 PPL(A)", "text_ro": "Folosit pentru alinierea cu obiectivele PPL(A) și structura actuală a instruirii.", "text_en": "Used to align with PPL(A) objectives and the current training structure."}, "FAA": {"label": "OFFICIAL CROSS-CHECK", "tone": "violet", "title_ro": "FAA Airplane Flying Handbook / Pilot’s Handbook", "title_en": "FAA Airplane Flying Handbook / Pilot’s Handbook", "text_ro": "A doua sursă oficială pentru aerodinamică, manevre de bază și energy management. Regulile FAA nu sunt aplicate ca reguli EASA.", "text_en": "A second official source for aerodynamics, basic manoeuvres, and energy management. FAA rules are not applied as EASA rules."}, "AFM": {"label": "AFM / POH CHECK", "tone": "amber", "title_ro": "Aircraft-specific", "title_en": "Aircraft-specific", "text_ro": "Vitezele, limitările, setările și secvențele exacte trebuie confirmate în AFM/POH, checklist-ul aprobat și cu instructorul.", "text_en": "Exact speeds, limitations, settings, and sequences must be confirmed in the AFM/POH, approved checklist, and with your instructor."}}, "requirements": [["45 h", "minimum flight instruction", "EASA FCL.210.A"], ["25 h", "minimum dual instruction", "EASA FCL.210.A"], ["10 h", "supervised solo", "EASA FCL.210.A"], ["5 h", "solo cross-country", "EASA FCL.210.A"], ["150 NM", "qualifying solo cross-country; full-stop landings at 2 other aerodromes", "EASA FCL.210.A"]], "theory": [["⚖", "Air Law & ATC Procedures", ["legal framework and organisations", "rules of the air", "air traffic services", "airspace and aerodromes", "documents and responsibilities"]], ["◉", "Human Performance", ["basic physiology", "vision and hearing", "hypoxia and hyperventilation", "stress and fatigue", "decision-making and human factors"]], ["☁", "Meteorology", ["atmosphere and pressure", "wind", "stability and clouds", "fronts and air masses", "weather hazards and interpretation"]], ["⌁", "Communications", ["VHF principles", "VFR phraseology", "routine calls", "urgency and distress", "readback and clearance confirmation"]], ["↗", "Principles of Flight", ["the four forces", "angle of attack", "stability", "flight controls", "stall and load factor"]], ["!", "Operational Procedures", ["normal and abnormal safety", "wake turbulence", "emergencies", "VFR operations", "threat and error management"]], ["∆", "Flight Performance & Planning", ["mass and balance", "take-off and landing performance", "climb and cruise", "fuel and endurance", "flight planning"]], ["⚙", "Aircraft General Knowledge", ["airframe and landing gear", "engine and propeller", "fuel and electrical systems", "instruments", "AFM/POH and limitations"]], ["⌖", "Navigation", ["charts and coordinates", "direction and magnetism", "dead reckoning", "wind triangle", "basic radio navigation"]]], "glossary": [["Angle of attack (AOA)", "Unghiul dintre referința aripii și relative airflow. Stall-ul apare când AOA critic este depășit.", "The angle between the wing reference and the relative airflow. A stall occurs when critical AOA is exceeded."], ["Attitude", "Orientarea avionului față de orizont, în special pitch și bank.", "The aeroplane’s orientation relative to the horizon, especially pitch and bank."], ["Aileron", "Suprafață principală de control pentru roll.", "Primary control surface for roll."], ["Elevator", "Suprafață principală de control pentru pitch.", "Primary control surface for pitch."], ["Rudder", "Suprafață principală de control pentru yaw.", "Primary control surface for yaw."], ["Pitch", "Rotație nose up / nose down în jurul axei laterale.", "Nose-up / nose-down rotation about the lateral axis."], ["Roll", "Rotație de bank în jurul axei longitudinale.", "Banking rotation about the longitudinal axis."], ["Yaw", "Rotație a nasului stânga-dreapta în jurul axei verticale.", "Left-right nose rotation about the vertical axis."], ["Lift", "Forță aerodinamică perpendiculară pe relative airflow.", "Aerodynamic force perpendicular to the relative airflow."], ["Drag", "Forță aerodinamică opusă mișcării prin aer.", "Aerodynamic force opposing motion through the air."], ["Thrust", "Forță propulsivă care contribuie la energia avionului.", "Propulsive force contributing to the aeroplane’s energy."], ["Weight", "Forța gravitațională care acționează asupra aeronavei.", "The gravitational force acting on the aircraft."], ["Trim", "Sistem folosit pentru reducerea presiunii continue pe comenzi într-o stare stabilizată.", "A system used to reduce continuous control pressure in a stabilised condition."], ["Coordinated flight", "Zbor în care yaw-ul și bank-ul sunt controlate pentru a reduce slip/skid-ul nedorit.", "Flight in which yaw and bank are controlled to reduce unwanted slip/skid."], ["Adverse yaw", "Tendința de yaw opusă direcției inițiale de roll la folosirea eleroanelor.", "The tendency to yaw opposite the initial roll direction when ailerons are used."], ["Load factor", "Raportul dintre lift și weight; crește în level turns pe măsură ce bank-ul crește.", "The ratio of lift to weight; it increases in level turns as bank increases."], ["Stall", "Pierderea caracteristică de portanță când critical AOA este depășit.", "The characteristic loss of lift when critical AOA is exceeded."], ["Slow flight", "Zbor la viteză mică, de obicei cu AOA mai mare și control authority redusă.", "Flight at low airspeed, usually with higher AOA and reduced control authority."], ["Glide", "Coborâre în care altitudinea furnizează energia necesară menținerii mișcării prin aer.", "A descent in which altitude supplies the energy needed to keep moving through the air."], ["Energy state", "Cantitatea și distribuția energiei între altitudine și viteză.", "The amount and distribution of energy between altitude and airspeed."], ["Induced drag", "Drag asociat producerii portanței, important la viteze mici și AOA mare.", "Drag associated with producing lift, important at low speed and high AOA."], ["AFM / POH", "Documentația aprobată/specifică din care vin limitările și procedurile exacte.", "Approved/specific documentation containing exact limitations and procedures."], ["Lookout", "Scanare vizuală sistematică pentru trafic, teren și situație.", "Systematic visual scanning for traffic, terrain, and the situation."], ["TEM", "Threat and Error Management — identificarea amenințărilor, erorilor și măsurilor de control.", "Threat and Error Management—identifying threats, errors, and controls."], ["VFR", "Visual Flight Rules — reguli și proceduri pentru operare vizuală aplicabilă.", "Visual Flight Rules—rules and procedures for applicable visual operations."]], "chapters": [
{"id": 1, "title_ro": "Aircraft Familiarisation", "title_en": "Aircraft Familiarisation", "time": "30 min", "pages": "Pooley Vol. 1 • Exercise 1 • printed pp. 1–12", "summary_ro": "Construiește o hartă mentală a avionului înainte să înveți manevrele: structură, axe, propulsie, cockpit și documentație specifică.", "summary_en": "Build a mental map of the aeroplane before learning manoeuvres: structure, axes, propulsion, cockpit, and aircraft-specific documentation.", "objectives_ro": ["numești principalele părți și rolul lor", "legi elevator/ailerons/rudder de pitch/roll/yaw", "înțelegi rolul motorului și elicei", "știi când informația trebuie verificată în AFM/POH"], "objectives_en": ["name the main parts and their roles", "connect elevator/ailerons/rudder to pitch/roll/yaw", "understand the engine and propeller roles", "know when information must be checked in the AFM/POH"], "sections": [{"title_ro": "Structura avionului", "title_en": "Aircraft structure", "body_ro": "Fuselajul este structura centrală care leagă aripile, ampenajul, trenul de aterizare, motorul și cockpitul. Aripile produc cea mai mare parte a portanței, iar ampenajul contribuie la stabilitate și control. Nu memora doar denumiri: leagă fiecare parte de funcția și riscul ei.", "body_en": "The fuselage is the central structure connecting the wings, tail unit, landing gear, engine, and cockpit. The wings produce most of the lift, while the tail unit contributes to stability and control. Do not memorise names only: connect each part to its function and risk.", "cockpit_ro": "La walk-around, privește avionul ca pe un sistem: suprafețe, balamale, fixări, prize, roți, lichide și capace. Ordinea exactă vine din checklist-ul aeronavei.", "cockpit_en": "During the walk-around, see the aeroplane as a system: surfaces, hinges, attachments, openings, wheels, fluids, and caps. The exact order comes from the aircraft checklist.", "mistake_ro": "Folosirea unei inspecții generice în locul checklist-ului specific avionului.", "mistake_en": "Using a generic inspection instead of the aircraft-specific checklist.", "sources": ["BOOK", "AFM"]}, {"title_ro": "Cele trei axe", "title_en": "The three axes", "body_ro": "Pitch este rotația nose up/down în jurul axei laterale, roll este bank-ul în jurul axei longitudinale, iar yaw este rotația stânga-dreapta în jurul axei verticale. Aproape orice manevră reală combină mai multe axe.", "body_en": "Pitch is nose-up/down rotation about the lateral axis, roll is banking about the longitudinal axis, and yaw is left-right rotation about the vertical axis. Almost every real manoeuvre combines more than one axis.", "cockpit_ro": "Model mental: elevator → pitch; ailerons → roll; rudder → yaw. Apoi adaugă coordonarea.", "cockpit_en": "Mental model: elevator → pitch; ailerons → roll; rudder → yaw. Then add coordination.", "mistake_ro": "A crede că rudder-ul singur „face virajul”. El controlează în primul rând yaw-ul; virajul normal cere bank și coordonare.", "mistake_en": "Believing the rudder alone “makes the turn.” It primarily controls yaw; a normal turn requires bank and coordination.", "sources": ["BOOK", "FAA"]}, {"title_ro": "Motor, elice și energie", "title_en": "Engine, propeller, and energy", "body_ro": "Motorul furnizează putere, iar elicea o transformă în tracțiune. Tracțiunea influențează energia totală a avionului, dar o schimbare de putere poate produce și tendințe de pitch și yaw, în funcție de aeronavă și regim.", "body_en": "The engine supplies power and the propeller converts it into thrust. Thrust influences the aeroplane’s total energy, but a power change can also create pitch and yaw tendencies depending on the aircraft and flight condition.", "cockpit_ro": "Nu memora o valoare de RPM sau o poziție de manetă ca regulă universală. Setările și limitările sunt aircraft-specific.", "cockpit_en": "Do not memorise one RPM value or lever position as a universal rule. Settings and limitations are aircraft-specific.", "mistake_ro": "A confunda „mai multă putere” cu „avionul va urca automat”. Rezultatul depinde de atitudine, viteză și energie.", "mistake_en": "Confusing “more power” with “the aeroplane will automatically climb.” The result depends on attitude, airspeed, and energy.", "sources": ["BOOK", "FAA", "AFM"]}, {"title_ro": "Cockpitul și sursele de informație", "title_en": "Cockpit information sources", "body_ro": "În VFR, exteriorul, sunetul, presiunea în comenzi și instrumentele construiesc împreună imaginea mentală a zborului. Instrumentele confirmă și cuantifică, dar fixarea pe un singur instrument poate distruge awareness-ul.", "body_en": "In VFR, the outside picture, sound, control feel, and instruments build the mental picture together. Instruments confirm and quantify, but fixation on one instrument can destroy awareness.", "cockpit_ro": "Folosește o buclă: afară → atitudine → scan scurt în interior → afară pentru lookout.", "cockpit_en": "Use a loop: outside → attitude → short inside scan → outside for lookout.", "mistake_ro": "Fixarea pe un singur instrument și pierderea imaginii de ansamblu.", "mistake_en": "Fixating on one instrument and losing the big picture.", "sources": ["BOOK", "FAA"]}], "quiz": [["Ce comandă controlează în principal roll-ul?", "Which control primarily controls roll?", ["Elevator", "Ailerons", "Rudder", "Flaps"], 1, "Eleroanele produc în principal roll.", "Ailerons primarily produce roll."], ["Yaw are loc în jurul axei…", "Yaw occurs about the…", ["longitudinale", "laterale", "verticale", "niciuneia"], 2, "Yaw este rotația în jurul axei verticale.", "Yaw is rotation about the vertical axis."], ["Ce document are prioritate pentru limitările exacte ale avionului?", "Which document takes priority for exact aircraft limitations?", ["Un rezumat generic", "AFM/POH aprobat", "Un forum", "Memoria pilotului"], 1, "Limitările și procedurile specifice se verifică în documentația aprobată.", "Aircraft-specific limitations and procedures are checked in the approved documentation."], ["În VFR de bază, instrumentele ar trebui să…", "In basic VFR, instruments should…", ["înlocuiască complet exteriorul", "confirme rapid imaginea exterioară", "fie ignorate", "fie urmărite continuu"], 1, "Exteriorul rămâne baza, iar instrumentele confirmă.", "The outside picture remains the foundation and instruments confirm it."], ["Motorul și elicea produc în principal…", "The engine and propeller primarily produce…", ["weight", "thrust", "yaw only", "lift directly"], 1, "Puterea motorului este transformată de elice în tracțiune.", "Engine power is converted by the propeller into thrust."]]},
{"id": 2, "title_ro": "Before and After Flight", "title_en": "Before and After Flight", "time": "35 min", "pages": "Pooley Vol. 1 • Exercises 2a–2c • printed pp. 13–24", "summary_ro": "Pregătirea începe înainte de pornirea motorului și se termină după securizarea avionului. Scopul este reducerea surprizelor prin verificări disciplinate.", "summary_en": "Preparation begins before engine start and ends after the aeroplane is secured. The aim is to reduce surprises through disciplined checks.", "objectives_ro": ["evaluezi pilotul, planul și aeronava", "înțelegi scopul walk-around-ului", "recunoști riscurile engine start", "închizi zborul prin post-flight și debrief"], "objectives_en": ["assess the pilot, plan, and aircraft", "understand the purpose of the walk-around", "recognise engine-start hazards", "close the flight with post-flight actions and debrief"], "sections": [{"title_ro": "Pilot, plan, aeronavă", "title_en": "Pilot, plan, aircraft", "body_ro": "O plecare bună combină trei întrebări: sunt eu apt să zbor, este zborul planificat în limite rezonabile și este avionul potrivit pentru misiune? Meteo, rută, combustibil, masă și centraj, documente și stare tehnică fac parte din aceeași decizie go/no-go.", "body_en": "A good departure combines three questions: am I fit to fly, is the flight planned within reasonable limits, and is the aeroplane suitable for the mission? Weather, route, fuel, mass and balance, documents, and technical condition belong to the same go/no-go decision.", "cockpit_ro": "Nu transforma pregătirea într-o colecție de checklist-uri separate. Gândește sistemic.", "cockpit_en": "Do not turn preparation into a collection of unrelated checklists. Think systemically.", "mistake_ro": "Bifarea itemilor fără a întreba ce risc verifici de fapt.", "mistake_en": "Ticking items without asking what risk you are actually checking.", "sources": ["BOOK", "EASA", "AFM"]}, {"title_ro": "Walk-around: caută anomalii", "title_en": "Walk-around: look for anomalies", "body_ro": "Scopul inspecției este detectarea condițiilor care pot afecta siguranța: deteriorări, blocaje, scurgeri, contaminare, capace, prize, roți și niveluri conform procedurii. Criteriile exacte sunt specifice aeronavei.", "body_en": "The purpose of the inspection is to detect conditions that can affect safety: damage, binding, leaks, contamination, caps, openings, wheels, and levels according to procedure. Exact criteria are aircraft-specific.", "cockpit_ro": "Folosește aceeași rută în jurul avionului pentru consistență, dar urmează checklist-ul aprobat.", "cockpit_en": "Use the same route around the aeroplane for consistency, but follow the approved checklist.", "mistake_ro": "Graba pentru că avionul a fost zburat recent de altcineva.", "mistake_en": "Rushing because the aeroplane was flown recently by someone else.", "sources": ["BOOK", "AFM"]}, {"title_ro": "Engine start este o operațiune de risc", "title_en": "Engine start is a risk operation", "body_ro": "Pornirea implică oameni, elice, obiecte libere, frâne, foc și sisteme electrice. Zona elicei trebuie tratată ca periculoasă, iar aeronava trebuie menținută sub control pe sol. Secvența exactă de start vine din checklist.", "body_en": "Starting involves people, propeller, loose objects, brakes, fire, and electrical systems. The propeller area must be treated as hazardous and the aircraft kept under control on the ground. The exact start sequence comes from the checklist.", "cockpit_ro": "Înainte de start: poziție sigură, zonă liberă și confirmarea că nimeni nu este expus.", "cockpit_en": "Before start: safe position, clear area, and confirmation that nobody is exposed to danger.", "mistake_ro": "Executarea pașilor corecți fără awareness asupra oamenilor și obiectelor din jur.", "mistake_en": "Performing the right steps without awareness of people and objects around the aircraft.", "sources": ["BOOK", "AFM"]}, {"title_ro": "Post-flight închide bucla", "title_en": "Post-flight closes the loop", "body_ro": "Zborul nu se termină când motorul se oprește. Aeronava trebuie securizată, observațiile și defectele trebuie raportate conform procedurii, iar pilotul trebuie să facă un debrief: ce a mers bine, ce a fost slab și ce trebuie revizuit.", "body_en": "The flight does not end when the engine stops. The aeroplane must be secured, observations and defects reported according to procedure, and the pilot should debrief: what went well, what was weak, and what needs review.", "cockpit_ro": "Notează una sau două lecții concrete pentru următorul zbor.", "cockpit_en": "Write down one or two concrete lessons for the next flight.", "mistake_ro": "A considera zborul terminat imediat după shutdown.", "mistake_en": "Considering the flight finished immediately after shutdown.", "sources": ["BOOK", "EASA", "AFM"]}], "quiz": [["Scopul principal al preflight-ului este…", "The main purpose of the preflight is…", ["să consumi timp", "să identifici condiții care pot afecta siguranța", "să cureți avionul", "să memorezi piese"], 1, "Preflight-ul caută anomalii și confirmă suitability pentru zbor.", "The preflight looks for anomalies and confirms suitability for flight."], ["Ordinea exactă a walk-around-ului vine din…", "The exact walk-around order comes from…", ["un video generic", "checklist-ul aeronavei", "memoria altui pilot", "alt tip de avion"], 1, "Procedura exactă este aircraft-specific.", "The exact procedure is aircraft-specific."], ["Zona elicei la engine start este…", "The propeller area during engine start is…", ["sigură", "periculoasă", "zonă pentru bagaje", "irelevantă"], 1, "Elicea este un hazard major.", "The propeller is a major hazard."], ["O decizie go/no-go bună combină…", "A good go/no-go decision combines…", ["doar vremea", "pilotul, planul și aeronava", "doar combustibilul", "doar ora"], 1, "Siguranța vine din evaluarea sistemului complet.", "Safety comes from assessing the whole system."], ["Post-flight-ul include…", "Post-flight includes…", ["doar coborârea din avion", "securizare, raportare și debrief", "doar alimentare", "doar fotografii"], 1, "Închiderea corectă include aeronava și învățarea pilotului.", "Proper closure includes both the aircraft and the pilot’s learning."]]},
{"id": 3, "title_ro": "Air Experience", "title_en": "Air Experience", "time": "25 min", "pages": "Pooley Vol. 1 • Exercise 3 • printed pp. 25–28", "summary_ro": "Prima experiență în aer este despre orientare: cum arată atitudinea, cum se simte avionul și cum îți împarți atenția între exterior și instrumente.", "summary_en": "The first airborne experience is about orientation: what attitude looks like, how the aeroplane feels, and how to divide attention between outside and instruments.", "objectives_ro": ["folosești exteriorul ca referință VFR principală", "faci scan-uri scurte în cockpit", "integrezi lookout-ul continuu", "începi să construiești situational awareness"], "objectives_en": ["use the outside picture as the primary VFR reference", "make short cockpit scans", "integrate continuous lookout", "begin building situational awareness"], "sections": [{"title_ro": "Exteriorul este fundația", "title_en": "The outside picture is the foundation", "body_ro": "În zbor vizual, orizontul și poziția avionului față de el sunt indicii puternice pentru pitch și bank. Instrumentele ajută la confirmare și precizie, dar nu ar trebui să consume toată atenția.", "body_en": "In visual flight, the horizon and the aeroplane’s position relative to it are strong cues for pitch and bank. Instruments help with confirmation and precision, but should not consume all attention.", "cockpit_ro": "Construiește o buclă: afară → atitudine → scan scurt în interior → afară.", "cockpit_en": "Build a loop: outside → attitude → short inside scan → outside.", "mistake_ro": "A încerca să „zbori instrumentele” într-o lecție VFR de bază.", "mistake_en": "Trying to “fly the instruments” in a basic VFR lesson.", "sources": ["BOOK", "FAA"]}, {"title_ro": "Lookout este continuu", "title_en": "Lookout is continuous", "body_ro": "Traficul poate apărea din direcții diferite și cu rate de apropiere greu de apreciat. Lookout-ul trebuie integrat în fiecare fază și manevră, nu făcut doar înainte de viraj.", "body_en": "Traffic can appear from different directions and with closure rates that are difficult to judge. Lookout must be integrated into every phase and manoeuvre, not performed only before a turn.", "cockpit_ro": "Scanează pe sectoare și lasă ochii să se oprească suficient pentru a detecta mișcarea.", "cockpit_en": "Scan in sectors and let your eyes pause long enough to detect movement.", "mistake_ro": "Scanare foarte rapidă fără fixări scurte.", "mistake_en": "Scanning too quickly without short pauses.", "sources": ["BOOK", "FAA"]}, {"title_ro": "Input mic → observă → ajustează", "title_en": "Small input → observe → adjust", "body_ro": "Controlul bun se construiește prin input mic, observarea răspunsului și o nouă corecție dacă este necesar. Comenzile mari și rapide pot crea oscilații și ascund relația cauză-efect.", "body_en": "Good control is built through a small input, observing the response, and making another correction if necessary. Large, rapid inputs can create oscillations and hide cause and effect.", "cockpit_ro": "Folosește ritmul input → wait → observe → refine.", "cockpit_en": "Use the rhythm input → wait → observe → refine.", "mistake_ro": "Chasing: corecții continue și prea mari după fiecare mișcare a unui instrument.", "mistake_en": "Chasing: continuous, excessive corrections after every instrument movement.", "sources": ["BOOK", "FAA"]}, {"title_ro": "Situational awareness", "title_en": "Situational awareness", "body_ro": "Pe lângă controlul avionului, începi să știi unde ești, ce face aeronava, ce urmează și ce amenințări există. Această imagine mentală trebuie întreținută, nu apare automat.", "body_en": "Beyond controlling the aeroplane, you begin to know where you are, what the aircraft is doing, what comes next, and what threats exist. This mental picture must be maintained; it does not appear automatically.", "cockpit_ro": "Întreabă-te periodic: aircraft state, position, next action, threats.", "cockpit_en": "Ask yourself periodically: aircraft state, position, next action, threats.", "mistake_ro": "Concentrarea completă pe o singură sarcină și pierderea imaginii de ansamblu.", "mistake_en": "Complete concentration on one task and losing the big picture.", "sources": ["BOOK", "EASA"]}], "quiz": [["În VFR de bază, referința principală pentru atitudine este…", "In basic VFR, the primary attitude reference is…", ["doar altimetrul", "imaginea exterioară", "doar GPS-ul", "doar radio-ul"], 1, "Exteriorul oferă referința principală.", "The outside picture provides the primary reference."], ["Lookout-ul ar trebui făcut…", "Lookout should be performed…", ["doar înainte de viraje", "continuu, integrat în zbor", "doar la sol", "doar de instructor"], 1, "Lookout-ul este o responsabilitate continuă.", "Lookout is a continuous responsibility."], ["O tehnică bună de corecție este…", "A good correction technique is…", ["input mare imediat", "input mic, observare, ajustare", "ignorarea răspunsului", "schimbarea tuturor comenzilor"], 1, "Corecțiile mici fac relația cauză-efect mai clară.", "Small corrections make cause and effect clearer."], ["Situational awareness include…", "Situational awareness includes…", ["doar altitudinea", "starea avionului, poziția, ce urmează și amenințările", "doar viteza", "doar vremea"], 1, "Este imaginea mentală a situației complete.", "It is the mental picture of the whole situation."], ["După un scan scurt în cockpit, în VFR privirea revine de regulă…", "After a short cockpit scan in VFR, the eyes normally return…", ["la un singur instrument", "afară", "la telefon", "nicăieri"], 1, "Revino afară pentru atitudine și lookout.", "Return outside for attitude and lookout."]]},
{"id": 4, "title_ro": "The Controls", "title_en": "The Controls", "time": "55 min", "pages": "Pooley Vol. 1 • Exercises 4a–4j • printed pp. 29–68", "summary_ro": "Comenzile nu sunt butoane izolate. Înveți efectul primar, efectele secundare, trim-ul și modul în care viteza, puterea și configurația schimbă răspunsul avionului.", "summary_en": "Controls are not isolated buttons. Learn primary effects, secondary effects, trim, and how airspeed, power, and configuration change the aeroplane’s response.", "objectives_ro": ["descrii efectele primare ale comenzilor", "înțelegi efectele secundare și coordonarea", "folosești trim-ul corect", "anticipezi efectele vitezei, puterii și flaps-urilor"], "objectives_en": ["describe primary control effects", "understand secondary effects and coordination", "use trim correctly", "anticipate the effects of airspeed, power, and flap"], "sections": [{"title_ro": "Efect primar vs. efecte ulterioare", "title_en": "Primary vs. further effects", "body_ro": "Elevatorul produce în principal pitch, eleroanele roll, iar rudder-ul yaw. Dar o comandă poate genera efecte ulterioare: bank-ul schimbă direcția liftului, eleroanele pot produce adverse yaw, iar o schimbare de putere poate crea tendințe de pitch și yaw.", "body_en": "The elevator primarily produces pitch, ailerons roll, and the rudder yaw. But a control can create further effects: bank changes lift direction, ailerons can produce adverse yaw, and a power change can create pitch and yaw tendencies.", "cockpit_ro": "Observă întâi efectul primar, apoi ce se dezvoltă în timp.", "cockpit_en": "Observe the primary effect first, then what develops over time.", "mistake_ro": "A considera că fiecare comandă afectează exclusiv o singură axă.", "mistake_en": "Assuming each control affects only one axis.", "sources": ["BOOK", "FAA"]}, {"title_ro": "Coordonarea", "title_en": "Coordination", "body_ro": "Pilotajul bun cere coordonarea axelor. Rudder-ul se folosește pentru yaw și balance, eleroanele pentru roll, iar elevatorul pentru pitch. Cantitatea corectă nu este o poziție memorată, ci răspunsul necesar în acel moment.", "body_en": "Good flying requires coordination of the axes. The rudder is used for yaw and balance, the ailerons for roll, and the elevator for pitch. The correct amount is not a memorised position but the response required at that moment.", "cockpit_ro": "Folosește exteriorul, direcția și indicatorul de balance pentru feedback.", "cockpit_en": "Use the outside picture, heading, and balance indicator for feedback.", "mistake_ro": "Rudder exagerat aplicat ca rețetă, nu ca răspuns la starea avionului.", "mistake_en": "Excessive rudder applied as a recipe rather than a response to the aeroplane’s state.", "sources": ["BOOK", "FAA"]}, {"title_ro": "Trim-ul reduce presiunea", "title_en": "Trim reduces pressure", "body_ro": "Trim-ul nu înlocuiește elevatorul. Mai întâi stabilești atitudinea și condiția de zbor, menții presiunea necesară, apoi trimezi pentru a elimina presiunea continuă.", "body_en": "Trim does not replace the elevator. First establish the attitude and flight condition, hold the required pressure, then trim to remove continuous pressure.", "cockpit_ro": "Control → stabilize → trim.", "cockpit_en": "Control → stabilise → trim.", "mistake_ro": "A „zbura cu trim-ul” în loc să setezi corect atitudinea.", "mistake_en": "“Flying with trim” instead of correctly setting the attitude.", "sources": ["BOOK", "FAA"]}, {"title_ro": "Viteza, puterea și flaps-urile schimbă răspunsul", "title_en": "Airspeed, power, and flap change the response", "body_ro": "Forțele pe suprafețele de control depind de airflow. La viteze mici, comenzile pot fi mai puțin eficiente; schimbările de putere pot modifica energia și tendințele de yaw/pitch; flaps-urile schimbă liftul, drag-ul și atitudinea necesară. Efectele exacte sunt aircraft-specific.", "body_en": "Forces on control surfaces depend on airflow. At low airspeed controls may be less effective; power changes can alter energy and yaw/pitch tendencies; flap changes lift, drag, and the required attitude. Exact effects are aircraft-specific.", "cockpit_ro": "Adaptează mărimea inputului la starea de energie și re-trimează după stabilizare.", "cockpit_en": "Adapt input size to the energy state and re-trim after stabilisation.", "mistake_ro": "A folosi aceeași amplitudine de comandă și aceleași setări în toate regimurile.", "mistake_en": "Using the same control amplitude and settings in every flight regime.", "sources": ["BOOK", "FAA", "AFM"]}], "quiz": [["Efectul primar al elevatorului este…", "The primary effect of the elevator is…", ["Roll", "Pitch", "Yaw", "Brake"], 1, "Elevatorul controlează în principal pitch-ul.", "The elevator primarily controls pitch."], ["De ce sunt necesare comenzi coordonate?", "Why are coordinated controls required?", ["Pentru că apar interacțiuni și efecte secundare", "Pentru baterie", "Doar pentru radio", "Nu sunt necesare"], 0, "Manevrele implică interacțiuni între axe.", "Manoeuvres involve interactions between axes."], ["Când trimezi?", "When do you trim?", ["Înainte de control", "După stabilizarea condiției", "În locul elevatorului", "Doar la sol"], 1, "Mai întâi controlezi și stabilizezi, apoi elimini presiunea.", "First control and stabilise, then remove pressure."], ["La viteză mică, control authority tinde să fie…", "At low airspeed, control authority tends to be…", ["mai redusă", "infinită", "fără legătură cu airflow-ul", "mereu mai mare"], 0, "Mai puțin airflow poate reduce eficiența comenzilor.", "Less airflow can reduce control effectiveness."], ["Limitările exacte pentru flaps se verifică în…", "Exact flap limitations are checked in…", ["AFM/POH", "un forum", "un alt avion", "memorie generică"], 0, "Limitările sunt aircraft-specific.", "Limitations are aircraft-specific."]]},
{"id": 5, "title_ro": "Taxiing an Aeroplane", "title_en": "Taxiing an Aeroplane", "time": "30 min", "pages": "Pooley Vol. 1 • Exercise 5 • printed pp. 69–76", "summary_ro": "Taxi-ul este pilotaj pe sol: controlul vitezei și direcției, awareness asupra întregii aeronave, vântului, traficului și instrucțiunilor.", "summary_en": "Taxiing is flying on the ground: controlling speed and direction while remaining aware of the whole aircraft, wind, traffic, and instructions.", "objectives_ro": ["controlezi viteza fără a lupta cu frânele", "menții direcția și clearance-ul wingtip-urilor", "înțelegi că steering-ul este aircraft-specific", "iei în calcul vântul și marja de oprire"], "objectives_en": ["control speed without fighting the brakes", "maintain direction and wingtip clearance", "understand that steering is aircraft-specific", "account for wind and stopping margin"], "sections": [{"title_ro": "Viteza trebuie să lase marjă de oprire", "title_en": "Speed must leave stopping margin", "body_ro": "Este nevoie de suficientă putere pentru a începe rulajul, apoi puterea se reduce la nivelul necesar pentru o viteză sigură. În zone aglomerate, înguste sau cu vizibilitate redusă, încetinește suplimentar.", "body_en": "Enough power is needed to start rolling, then power is reduced to the level needed for a safe speed. In congested, narrow, or low-visibility areas, slow down further.", "cockpit_ro": "Întreabă-te: pot opri sigur în distanța pe care o văd liberă?", "cockpit_en": "Ask: can I stop safely within the distance I can see is clear?", "mistake_ro": "Menținerea unei viteze prea mari pentru spațiul disponibil.", "mistake_en": "Maintaining too much speed for the available space.", "sources": ["BOOK", "FAA", "AFM"]}, {"title_ro": "Putere și frâne", "title_en": "Power and brakes", "body_ro": "Pentru încetinire, redu puterea și folosește frânele conform necesității și procedurii. Puterea mare împotriva frânelor creează căldură și uzură.", "body_en": "To slow down, reduce power and use brakes as required and according to procedure. High power against the brakes creates heat and wear.", "cockpit_ro": "Controlează viteza din putere înainte de a cere frânelor să repare excesul de viteză.", "cockpit_en": "Control speed with power before asking the brakes to fix excess speed.", "mistake_ro": "Folosirea frânelor pentru a controla o viteză creată de prea multă putere.", "mistake_en": "Using the brakes to control speed created by too much power.", "sources": ["BOOK", "FAA", "AFM"]}, {"title_ro": "Steering și dimensiunile aeronavei", "title_en": "Steering and aircraft dimensions", "body_ro": "Sistemul de steering diferă între aeronave: nosewheel steering, caster, differential braking sau combinații. În viraje, wingtip-urile și coada urmează trasee diferite de cockpit.", "body_en": "Steering systems differ between aircraft: nosewheel steering, caster, differential braking, or combinations. In turns, the wing tips and tail follow paths different from the cockpit.", "cockpit_ro": "Privește traseul întregii aeronave, nu doar roata din față.", "cockpit_en": "Watch the path of the whole aircraft, not just the nosewheel.", "mistake_ro": "Clearance suficient pentru cockpit, dar nu pentru wingtip.", "mistake_en": "Enough clearance for the cockpit, but not for the wing tip.", "sources": ["BOOK", "FAA", "AFM"]}, {"title_ro": "Vântul contează și pe sol", "title_en": "Wind matters on the ground", "body_ro": "Vântul poate crea weathervaning și poate încărca suprafețele de control. Poziția comenzilor pentru taxi în vânt depinde de direcția vântului, configurație și aeronavă.", "body_en": "Wind can create weathervaning and load the control surfaces. Control positioning for taxi in wind depends on wind direction, configuration, and aircraft.", "cockpit_ro": "Folosește tehnica predată de instructor și recomandată pentru avionul tău.", "cockpit_en": "Use the technique taught by your instructor and recommended for your aeroplane.", "mistake_ro": "Ignorarea rafalelor doar pentru că avionul este pe sol.", "mistake_en": "Ignoring gusts just because the aeroplane is on the ground.", "sources": ["BOOK", "FAA", "AFM"]}], "quiz": [["Primul mod de a reduce viteza la taxi este de regulă…", "The first way to reduce taxi speed is generally…", ["mai multă putere", "reducerea puterii", "flaps full", "rudder maxim"], 1, "Reducerea puterii permite încetinirea fără a lupta cu frânele.", "Reducing power allows slowing without fighting the brakes."], ["De ce eviți puterea mare împotriva frânelor?", "Why avoid high power against the brakes?", ["Crește căldura și uzura", "Oprește radio-ul", "Crește liftul la zero", "Nu are efect"], 0, "Este ineficient și poate supraîncălzi/uzura frânele.", "It is inefficient and can overheat/wear the brakes."], ["În viraj strâns la sol trebuie urmărite…", "In a tight ground turn you must watch…", ["wingtip-urile și coada", "doar vitezometrul", "numai busola", "nimic"], 0, "Întreaga aeronavă are propriul traseu.", "The whole aircraft has its own path."], ["Sistemul exact de steering este…", "The exact steering system is…", ["identic la toate avioanele", "aircraft-specific", "irelevant", "doar electric"], 1, "Sistemele diferă între aeronave.", "Systems differ between aircraft."], ["O întrebare bună pentru viteza de taxi este…", "A good question for taxi speed is…", ["Pot opri în distanța liberă pe care o văd?", "Pot ajunge cât mai repede?", "Cât de tare sună motorul?", "Pot evita checklist-ul?"], 0, "Marja de oprire este un criteriu practic de siguranță.", "Stopping margin is a practical safety criterion."]]},
{"id": 6, "title_ro": "Straight and Level", "title_en": "Straight and Level", "time": "45 min", "pages": "Pooley Vol. 1 • Exercises 6a–6c • printed pp. 77–102", "summary_ro": "Zborul drept și nivelat este laboratorul în care înveți relația dintre atitudine, putere, viteză, balance și trim.", "summary_en": "Straight-and-level flight is the laboratory where you learn the relationship between attitude, power, airspeed, balance, and trim.", "objectives_ro": ["menții direcția și altitudinea prin referințe externe și confirmare instrumentală", "înțelegi că o nouă viteză cere o nouă stare stabilizată", "folosești balance și trim corect", "recunoști trendurile înainte ca deviațiile să devină mari"], "objectives_en": ["maintain direction and altitude using outside references and instrument confirmation", "understand that a new airspeed requires a new stabilised state", "use balance and trim correctly", "recognise trends before deviations become large"], "sections": [{"title_ro": "Atitudinea este o imagine", "title_en": "Attitude is a picture", "body_ro": "În VFR, pitch și bank sunt recunoscute în primul rând prin poziția avionului față de orizont. Instrumentele confirmă altitudinea, direcția și viteza, dar corecția începe de obicei prin revenirea la imaginea corectă a atitudinii.", "body_en": "In VFR, pitch and bank are recognised primarily by the aeroplane’s position relative to the horizon. Instruments confirm altitude, heading, and airspeed, but correction usually starts by restoring the correct attitude picture.", "cockpit_ro": "Folosește repere stabile pe capotă și orizont, apoi fă scan-uri scurte pentru confirmare.", "cockpit_en": "Use stable references on the cowling and horizon, then make short scans for confirmation.", "mistake_ro": "A încerca să corectezi altimetrul fără să corectezi clar atitudinea care a produs trendul.", "mistake_en": "Trying to correct the altimeter without clearly correcting the attitude that created the trend.", "sources": ["BOOK", "FAA"]}, {"title_ro": "Putere + atitudine = stare stabilizată", "title_en": "Power + attitude = stabilised state", "body_ro": "La aceeași configurație și masă, o viteză stabilizată diferită cere de regulă o combinație diferită de putere și atitudine. Nu există o singură comandă care să controleze singură altitudinea sau viteza în toate situațiile.", "body_en": "At the same configuration and mass, a different stabilised airspeed generally requires a different combination of power and attitude. No single control independently controls altitude or airspeed in every situation.", "cockpit_ro": "Gândește în energie: throttle-ul influențează energia totală, iar elevatorul schimbă modul în care energia este distribuită între altitudine și viteză.", "cockpit_en": "Think in energy: the throttle influences total energy, while the elevator changes how energy is distributed between altitude and airspeed.", "mistake_ro": "A aplica rigid sloganul «pitch pentru X, power pentru Y» fără a observa starea reală a avionului.", "mistake_en": "Rigidly applying a “pitch for X, power for Y” slogan without observing the aeroplane’s actual state.", "sources": ["BOOK", "FAA"]}, {"title_ro": "Balance și coordonare", "title_en": "Balance and coordination", "body_ro": "Zborul coordonat reduce slip-ul sau skid-ul nedorit și face comportamentul avionului mai previzibil. Rudder-ul controlează yaw-ul și coordonează efectele celorlalte comenzi; nu este o poziție fixă, ci o presiune adaptată situației.", "body_en": "Coordinated flight reduces unwanted slip or skid and makes the aeroplane’s behaviour more predictable. The rudder controls yaw and coordinates the effects of the other controls; it is not a fixed position but pressure adapted to the situation.", "cockpit_ro": "Folosește presiuni fine și confirmă prin imaginea exterioară, direcție și indicatorul de balance.", "cockpit_en": "Use fine pressures and confirm with the outside picture, heading, and balance indicator.", "mistake_ro": "A folosi «step on the ball» mecanic, fără să înțelegi ce face avionul.", "mistake_en": "Using “step on the ball” mechanically without understanding what the aeroplane is doing.", "sources": ["BOOK", "FAA"]}, {"title_ro": "Schimbarea vitezei și trim-ul", "title_en": "Changing airspeed and trim", "body_ro": "Când selectezi o viteză nouă, avionul trece printr-o fază tranzitorie. Pilotul menține direcția și altitudinea dorită, anticipează schimbarea de atitudine și re-trimează numai după ce noua condiție este suficient de stabilă.", "body_en": "When selecting a new airspeed, the aeroplane passes through a transient phase. The pilot maintains the desired heading and altitude, anticipates the attitude change, and re-trims only after the new condition is sufficiently stable.", "cockpit_ro": "Control → așteaptă trendul → stabilizează → trim.", "cockpit_en": "Control → wait for the trend → stabilise → trim.", "mistake_ro": "A trima continuu în timp ce viteza încă se schimbă rapid, apoi a retrima din nou și din nou.", "mistake_en": "Trimming continuously while airspeed is still changing rapidly, then re-trimming again and again.", "sources": ["BOOK", "FAA"]}, {"title_ro": "Scan-ul bun vede trendul devreme", "title_en": "A good scan sees the trend early", "body_ro": "O deviație mică de pitch poate deveni în timp o deviație de altitudine și viteză. Pilotul bun observă trendul devreme și face o corecție mică, în loc să aștepte o abatere mare.", "body_en": "A small pitch deviation can develop into an altitude and airspeed deviation. A good pilot notices the trend early and makes a small correction rather than waiting for a large error.", "cockpit_ro": "Afară pentru atitudine și trafic; înăuntru pentru trenduri și confirmare; apoi afară din nou.", "cockpit_en": "Outside for attitude and traffic; inside for trends and confirmation; then outside again.", "mistake_ro": "Instrument chasing: fiecare ac care se mișcă produce imediat o nouă corecție.", "mistake_en": "Instrument chasing: every moving needle immediately triggers another correction.", "sources": ["BOOK", "FAA"]}], "quiz": [["În VFR, pitch-ul este recunoscut inițial cel mai bine prin…", "In VFR, pitch is initially best recognised by…", ["imaginea avionului față de orizont", "doar GPS", "doar radio", "numai ceas"], 0, "Atitudinea vizuală este referința primară.", "The visual attitude picture is the primary reference."], ["O viteză stabilizată diferită cere de regulă…", "A different stabilised airspeed generally requires…", ["aceeași putere și aceeași atitudine", "o nouă combinație de putere și atitudine", "doar rudder", "doar flaps"], 1, "O nouă stare stabilizată cere o nouă combinație de energie și atitudine.", "A new stabilised state requires a new combination of energy and attitude."], ["Trim-ul se aplică în principal…", "Trim is mainly applied…", ["înainte de control", "după stabilizare", "în locul elevatorului", "doar la sol"], 1, "Mai întâi stabilești starea, apoi elimini presiunea continuă.", "First establish the condition, then remove continuous pressure."], ["Scopul unui scan bun este să…", "The purpose of a good scan is to…", ["detecteze trendurile devreme", "fixeze un singur instrument", "ignore traficul", "înlocuiască exteriorul"], 0, "Trendurile mici sunt mai ușor de corectat decât deviațiile mari.", "Small trends are easier to correct than large deviations."], ["În modelul de energie, throttle-ul influențează în principal…", "In the energy model, the throttle mainly influences…", ["energia totală", "doar yaw", "doar bank", "doar busola"], 0, "Thrust versus drag schimbă energia totală a avionului.", "Thrust versus drag changes the aeroplane’s total energy."], ["Rudder-ul în straight and level ajută la…", "In straight-and-level flight the rudder helps to…", ["coordoneze yaw și balance", "crească direct liftul", "controleze frânele în aer", "seteze altimetrul"], 0, "Rudder-ul ajută la menținerea zborului coordonat.", "The rudder helps maintain coordinated flight."]]},
{"id": 7, "title_ro": "Climbing", "title_en": "Climbing", "time": "35 min", "pages": "Pooley Vol. 1 • Exercise 7 • printed pp. 103–114", "summary_ro": "Urcarea transformă surplusul de energie în altitudine. Pilotul coordonează puterea, atitudinea, viteza, balance-ul, răcirea și lookout-ul.", "summary_en": "A climb converts surplus energy into altitude. The pilot coordinates power, attitude, airspeed, balance, cooling, and lookout.", "objectives_ro": ["stabilești o urcare controlată", "menții viteza țintă prin atitudine și energie", "anticipezi efectele puterii și vizibilitatea redusă", "nivelezi cu anticipare"], "objectives_en": ["establish a controlled climb", "maintain target airspeed through attitude and energy", "anticipate power effects and reduced visibility", "level off with anticipation"], "sections": [{"title_ro": "De ce urcă avionul?", "title_en": "Why does the aeroplane climb?", "body_ro": "Pentru a crește altitudinea, avionul trebuie să transforme o parte din energia disponibilă în energie potențială. Puterea disponibilă, drag-ul, masa, densitatea aerului și viteza influențează performanța de urcare.", "body_en": "To gain altitude, the aeroplane must convert some available energy into potential energy. Available power, drag, mass, air density, and airspeed influence climb performance.", "cockpit_ro": "Gândește «energy in, energy distribution», nu doar «nasul sus = urcare».", "cockpit_en": "Think “energy in, energy distribution,” not simply “nose up = climb.”", "mistake_ro": "A ridica excesiv nasul fără suficientă energie, consumând viteza.", "mistake_en": "Raising the nose excessively without enough energy and using up airspeed.", "sources": ["BOOK", "FAA"]}, {"title_ro": "Puterea și viteza de urcare", "title_en": "Power and climb airspeed", "body_ro": "După stabilirea puterii conform procedurii aeronavei, atitudinea se ajustează pentru viteza de urcare dorită. Dacă viteza scade sub țintă, pitch-ul trebuie redus suficient; dacă viteza este prea mare, pitch-ul poate fi crescut, în cadrul unei tehnici coordonate.", "body_en": "After setting power according to the aircraft procedure, attitude is adjusted for the desired climb airspeed. If airspeed falls below target, pitch must be reduced sufficiently; if airspeed is too high, pitch may be increased within a coordinated technique.", "cockpit_ro": "Folosește outside attitude, apoi confirmă trendul de airspeed. Valorile exacte vin din AFM/POH.", "cockpit_en": "Use the outside attitude, then confirm the airspeed trend. Exact values come from the AFM/POH.", "mistake_ro": "Corecții mari de pitch pentru deviații mici de viteză.", "mistake_en": "Large pitch corrections for small airspeed deviations.", "sources": ["BOOK", "FAA", "AFM"]}, {"title_ro": "Puterea poate crea tendințe de yaw", "title_en": "Power can create yaw tendencies", "body_ro": "La putere mare și viteză relativ mică, avioanele cu elice pot prezenta tendințe mai pronunțate de yaw. Cantitatea de rudder necesară depinde de aeronavă și de condiția de zbor.", "body_en": "At high power and relatively low airspeed, propeller aeroplanes can show stronger yaw tendencies. The amount of rudder required depends on the aircraft and flight condition.", "cockpit_ro": "Menține direcția și balance-ul prin presiunea necesară, nu printr-o poziție memorată a pedalei.", "cockpit_en": "Maintain heading and balance with the pressure required, not with a memorised pedal position.", "mistake_ro": "A aplica «right rudder» ca slogan fix fără a observa rezultatul.", "mistake_en": "Applying “right rudder” as a fixed slogan without observing the result.", "sources": ["BOOK", "FAA", "AFM"]}, {"title_ro": "Lookout în urcare", "title_en": "Lookout in the climb", "body_ro": "Atitudinea nose-high poate reduce vizibilitatea înainte și în jos. Lookout-ul trebuie menținut printr-o tehnică adecvată situației și procedurilor locale, fără a pierde controlul avionului.", "body_en": "A nose-high attitude can reduce forward and downward visibility. Lookout must be maintained using a technique appropriate to the situation and local procedures without losing control of the aeroplane.", "cockpit_ro": "Folosește rutina predată de instructor pentru a vedea zonele ascunse de nas.", "cockpit_en": "Use the routine taught by your instructor to see areas hidden by the nose.", "mistake_ro": "O urcare lungă fără scanarea spațiului ascuns de nas.", "mistake_en": "A long climb without scanning the area hidden by the nose.", "sources": ["BOOK", "FAA", "AFM"]}, {"title_ro": "Level-off: anticipează", "title_en": "Level-off: anticipate", "body_ro": "Pentru nivelare, schimbarea de pitch începe înainte de altitudinea țintă. Cât de devreme depinde de rata de urcare și răspunsul avionului. Apoi avionul accelerează spre noua stare, puterea se ajustează și se re-trimează.", "body_en": "For level-off, the pitch change begins before the target altitude. How early depends on the rate of climb and the aeroplane’s response. The aircraft then accelerates toward the new condition, power is adjusted, and the aeroplane is re-trimmed.", "cockpit_ro": "Cu cât rata de urcare este mai mare, cu atât ai nevoie de mai multă anticipare.", "cockpit_en": "The higher the rate of climb, the more anticipation you need.", "mistake_ro": "A aștepta altitudinea țintă înainte de a începe nivelarea.", "mistake_en": "Waiting until the target altitude before beginning the level-off.", "sources": ["BOOK", "FAA", "AFM"]}], "quiz": [["O urcare reprezintă în principal…", "A climb mainly represents…", ["transformarea surplusului de energie în altitudine", "doar creșterea pitch-ului", "doar mai mult RPM", "doar rudder"], 0, "Urcarea este o problemă de energie și performanță, nu doar de atitudine.", "Climbing is an energy and performance problem, not just an attitude change."], ["Viteza de urcare dorită este controlată în mare parte prin…", "Desired climb airspeed is controlled largely by…", ["atitudine/pitch în cadrul stării de putere", "frâne", "radio", "busolă"], 0, "După setarea puterii conform procedurii, pitch-ul este ajustat pentru airspeed.", "After setting power according to procedure, pitch is adjusted for airspeed."], ["La putere mare și viteză mică, yaw tendencies pot fi…", "At high power and low airspeed, yaw tendencies may be…", ["mai pronunțate", "imposibile", "identice la toate avioanele", "fără legătură cu propulsia"], 0, "Efectele propulsive pot deveni mai pronunțate.", "Propulsive effects can become more pronounced."], ["De ce lookout-ul în urcare cere atenție specială?", "Why does lookout in a climb require special attention?", ["Nasul poate ascunde trafic înainte/în jos", "Instrumentele dispar", "Aripile se scurtează", "Radio-ul nu merge"], 0, "Atitudinea de urcare poate limita vizibilitatea.", "The climb attitude can limit visibility."], ["Level-off-ul începe de regulă…", "Level-off generally begins…", ["după depășirea altitudinii", "înainte de altitudinea țintă, cu anticipare", "exact la țintă indiferent de ROC", "doar când scade viteza"], 1, "Este necesară anticipare pentru a evita overshoot-ul.", "Anticipation is required to avoid overshoot."], ["Setările exacte de putere și vitezele de urcare vin din…", "Exact climb power settings and speeds come from…", ["AFM/POH și procedura avionului", "o regulă universală", "un alt avion", "doar internet"], 0, "Valorile sunt aircraft-specific.", "The values are aircraft-specific."]]},
{"id": 8, "title_ro": "Descending", "title_en": "Descending", "time": "45 min", "pages": "Pooley Vol. 1 • Exercises 8a–8d • printed pp. 115–136", "summary_ro": "Coborârea este managementul pierderii de energie. Diferența dintre glide și powered descent schimbă sursa energiei și modul în care controlezi profilul.", "summary_en": "A descent is management of energy loss. The difference between a glide and a powered descent changes the energy source and how you control the profile.", "objectives_ro": ["diferențiezi glide de powered descent", "menții viteza și profilul prin coordonarea comenzilor", "înțelegi efectele flaps-urilor", "înțelegi rolul și riscurile sideslip-ului"], "objectives_en": ["distinguish a glide from a powered descent", "maintain airspeed and profile through coordinated controls", "understand flap effects", "understand the role and risks of a sideslip"], "sections": [{"title_ro": "Glide: altitudinea devine energie", "title_en": "Glide: altitude becomes energy", "body_ro": "Cu putere redusă sau absentă, avionul pierde energie potențială prin coborâre pentru a susține viteza și a învinge drag-ul. Atitudinea este folosită pentru a menține viteza de glide dorită.", "body_en": "With reduced or no power, the aeroplane loses potential energy by descending in order to sustain airspeed and overcome drag. Attitude is used to maintain the desired glide speed.", "cockpit_ro": "Nu încerca să «ții avionul sus» prin creșterea continuă a pitch-ului; poți consuma viteza și reduce marja față de stall.", "cockpit_en": "Do not try to “hold the aeroplane up” by continuously increasing pitch; you can use up airspeed and reduce stall margin.", "mistake_ro": "A confunda reducerea ratei de coborâre cu tragerea continuă de manșă.", "mistake_en": "Confusing a lower rate of descent with continuously pulling back.", "sources": ["BOOK", "FAA"]}, {"title_ro": "Powered descent", "title_en": "Powered descent", "body_ro": "Într-un powered descent, motorul rămâne parte din managementul energiei. Puterea poate fi folosită pentru a regla energia totală și profilul, în timp ce atitudinea și viteza trebuie coordonate pentru rezultatul dorit.", "body_en": "In a powered descent, the engine remains part of energy management. Power can be used to regulate total energy and flight path, while attitude and airspeed must be coordinated for the desired result.", "cockpit_ro": "O schimbare de putere poate cere o schimbare de atitudine și re-trim după stabilizare.", "cockpit_en": "A power change can require an attitude change and re-trim after stabilisation.", "mistake_ro": "A reduce puterea fără a anticipa efectul asupra pitch-ului, yaw-ului și vitezei.", "mistake_en": "Reducing power without anticipating effects on pitch, yaw, and airspeed.", "sources": ["BOOK", "FAA", "AFM"]}, {"title_ro": "Flaps în coborâre", "title_en": "Flap in descent", "body_ro": "Flaps-urile schimbă liftul și drag-ul și pot permite un profil mai abrupt la o viteză controlată. Efectul exact, limitările și ordinea de selectare sunt specifice avionului.", "body_en": "Flaps change lift and drag and can allow a steeper profile at a controlled airspeed. Exact effects, limitations, and selection sequence are aircraft-specific.", "cockpit_ro": "Selectează configurația în limite, anticipează tendința de pitch și menține viteza sub control.", "cockpit_en": "Select configuration within limits, anticipate the pitch tendency, and keep airspeed under control.", "mistake_ro": "A folosi flap-ul ca soluție tardivă pentru o stare de energie prost planificată.", "mistake_en": "Using flap as a late solution to a poorly planned energy state.", "sources": ["BOOK", "FAA", "AFM"]}, {"title_ro": "Sideslip: necoordonat intenționat", "title_en": "Sideslip: intentionally uncoordinated", "body_ro": "Un sideslip intenționat folosește comenzi încrucișate pentru a crea o stare necoordonată controlată, de obicei pentru a crește drag-ul sau a modifica geometria față de vânt. Tehnica și limitările depind de aeronavă.", "body_en": "An intentional sideslip uses crossed controls to create a controlled uncoordinated condition, usually to increase drag or change geometry relative to the wind. Technique and limitations depend on the aircraft.", "cockpit_ro": "Distinge un sideslip intenționat de un skid nedorit în apropierea stall-ului.", "cockpit_en": "Distinguish an intentional sideslip from an unwanted skid near the stall.", "mistake_ro": "A trata toate stările cu ball off-centre ca fiind echivalente.", "mistake_en": "Treating every ball-off-centre condition as equivalent.", "sources": ["BOOK", "FAA", "AFM"]}, {"title_ro": "Level-off din coborâre", "title_en": "Level-off from descent", "body_ro": "Pentru a opri coborârea trebuie anticipată inerția. Pilotul coordonează atitudinea și energia disponibilă, apoi stabilizează noua stare și trimează.", "body_en": "To stop the descent, inertia must be anticipated. The pilot coordinates attitude and available energy, then stabilises the new condition and trims.", "cockpit_ro": "Nu aștepta altitudinea țintă pentru prima corecție atunci când rata de coborâre este mare.", "cockpit_en": "Do not wait until the target altitude for the first correction when the rate of descent is high.", "mistake_ro": "Overshoot sub altitudine urmat de o corecție bruscă.", "mistake_en": "Overshooting below altitude followed by an abrupt correction.", "sources": ["BOOK", "FAA"]}], "quiz": [["În glide, energia pentru menținerea zborului vine în mare parte din…", "In a glide, energy to sustain flight comes largely from…", ["pierderea de altitudine", "frâne", "radio", "baterie"], 0, "Altitudinea este convertită în energia necesară mișcării prin aer.", "Altitude is converted into the energy needed to move through the air."], ["Într-un powered descent, power poate fi folosită pentru…", "In a powered descent, power can be used to…", ["regla energia totală și profilul", "doar a porni radio-ul", "elimina drag-ul", "schimba vremea"], 0, "Puterea rămâne parte din managementul energiei.", "Power remains part of energy management."], ["Flaps-urile tind să…", "Flaps tend to…", ["schimbe liftul și drag-ul", "nu schimbe nimic", "controleze doar yaw", "oprească motorul"], 0, "Configurația modifică caracteristicile aerodinamice.", "Configuration changes aerodynamic characteristics."], ["Un sideslip intenționat este…", "An intentional sideslip is…", ["o stare necoordonată controlată", "întotdeauna un stall", "un instrument defect", "un radio call"], 0, "Este o utilizare controlată a comenzilor încrucișate, în limitele avionului.", "It is a controlled use of crossed controls within aircraft limits."], ["De ce nu tragi continuu de manșă într-un glide pentru a «ține avionul sus»?", "Why not keep pulling back in a glide to “hold the aeroplane up”?", ["Poți pierde airspeed și stall margin", "Crește fuel flow la zero", "Oprește GPS-ul", "Nu se întâmplă nimic"], 0, "Creșterea AOA poate consuma viteza și apropia stall-ul.", "Increasing AOA can use up airspeed and bring the aeroplane closer to the stall."], ["Tehnica exactă de sideslip și limitările se verifică în…", "Exact sideslip technique and limitations are checked in…", ["AFM/POH și cu instructorul", "o regulă universală", "un alt tip de avion", "doar busolă"], 0, "Utilizarea poate fi aircraft-specific.", "Use can be aircraft-specific."]]},
{"id": 9, "title_ro": "Turning", "title_en": "Turning", "time": "50 min", "pages": "Pooley Vol. 1 • Exercises 9a–9d • printed pp. 137–166", "summary_ro": "Un viraj schimbă direcția vectorului de portanță. Ca să menții altitudinea și coordonarea, gestionezi bank, pitch, power, rudder și lookout.", "summary_en": "A turn changes the direction of the lift vector. To maintain altitude and coordination, you manage bank, pitch, power, rudder, and lookout.", "objectives_ro": ["înțelegi de ce bank-ul produce viraj", "menții altitudinea și balance-ul", "anticipezi efectul bank-ului asupra load factor și stall margin", "ieși pe un heading selectat cu anticipare"], "objectives_en": ["understand why bank produces a turn", "maintain altitude and balance", "anticipate the effect of bank on load factor and stall margin", "roll out on a selected heading with anticipation"], "sections": [{"title_ro": "De ce avionul virează când este banked", "title_en": "Why the aeroplane turns when banked", "body_ro": "În zbor nivelat, lift-ul este orientat în principal în sus. Când avionul este înclinat, vectorul de lift se înclină și apare o componentă orizontală care schimbă direcția traiectoriei.", "body_en": "In level flight, lift is directed mainly upward. When the aeroplane is banked, the lift vector tilts and a horizontal component appears that changes the direction of the flight path.", "cockpit_ro": "Bank-ul creează mecanismul principal al virajului; rudder-ul coordonează yaw-ul, nu înlocuiește bank-ul.", "cockpit_en": "Bank creates the main turning mechanism; the rudder coordinates yaw, it does not replace bank.", "mistake_ro": "A încerca să virezi doar «cu pedala», fără bank adecvat.", "mistake_en": "Trying to turn only “with the pedal,” without appropriate bank.", "sources": ["BOOK", "FAA"]}, {"title_ro": "Menținerea altitudinii cere mai mult lift total", "title_en": "Maintaining altitude requires more total lift", "body_ro": "Când vectorul de lift este înclinat, componenta verticală scade dacă lift-ul total rămâne neschimbat. Pentru un level turn, pilotul trebuie să crească lift-ul total, de obicei printr-o combinație de AOA și, după caz, power.", "body_en": "When the lift vector is tilted, its vertical component decreases if total lift remains unchanged. For a level turn, the pilot must increase total lift, usually through a combination of AOA and, where appropriate, power.", "cockpit_ro": "Cu bank mai mare, cerința de lift și load factor cresc.", "cockpit_en": "With more bank, the lift requirement and load factor increase.", "mistake_ro": "A crește bank-ul fără ajustarea necesară pentru altitudine și viteză.", "mistake_en": "Increasing bank without the adjustment required for altitude and airspeed.", "sources": ["BOOK", "FAA"]}, {"title_ro": "Coordonarea și adverse yaw", "title_en": "Coordination and adverse yaw", "body_ro": "Aileron input poate produce adverse yaw, iar avionul poate slip-ui sau skid-ui dacă rudder-ul nu este potrivit. Coordonarea înseamnă folosirea comenzilor astfel încât avionul să urmeze traiectoria dorită fără yaw nedorit.", "body_en": "Aileron input can produce adverse yaw, and the aeroplane may slip or skid if rudder use is inappropriate. Coordination means using the controls so the aeroplane follows the desired path without unwanted yaw.", "cockpit_ro": "Privește afară pentru direcția nasului și bank, apoi confirmă balance-ul.", "cockpit_en": "Look outside for nose direction and bank, then confirm balance.", "mistake_ro": "Rudder prea mult sau prea puțin, corectat târziu.", "mistake_en": "Too much or too little rudder, corrected late.", "sources": ["BOOK", "FAA"]}, {"title_ro": "Bank, load factor și stall margin", "title_en": "Bank, load factor, and stall margin", "body_ro": "Într-un level turn, pe măsură ce bank-ul crește, load factor-ul crește. Un load factor mai mare crește și stall speed pentru configurația respectivă. De aceea un viraj mai abrupt reduce stall margin la aceeași IAS.", "body_en": "In a level turn, as bank increases, load factor increases. A higher load factor also increases stall speed for the configuration. A steeper turn therefore reduces stall margin at the same IAS.", "cockpit_ro": "Înțelege relația: mai mult load factor → stall speed mai mare.", "cockpit_en": "Understand the relationship: more load factor → higher stall speed.", "mistake_ro": "A crede că stall-ul în bank apare doar la viteza publicată de stall pentru 1G.", "mistake_en": "Believing a banked stall occurs only at the published 1G stall speed.", "sources": ["BOOK", "FAA"]}, {"title_ro": "Roll-out pe heading", "title_en": "Rolling out on heading", "body_ro": "Pentru a ieși pe un heading selectat, roll-out-ul începe înainte de heading-ul țintă. Cantitatea de anticipare depinde de bank, rata de viraj și răspunsul avionului.", "body_en": "To roll out on a selected heading, the roll-out begins before the target heading. The amount of anticipation depends on bank, rate of turn, and aircraft response.", "cockpit_ro": "Alege un lead point, începe roll-out-ul și ajustează fin pe măsură ce bank-ul se reduce.", "cockpit_en": "Choose a lead point, begin the roll-out, and refine as bank decreases.", "mistake_ro": "A menține bank-ul până exact la heading, apoi a face overshoot.", "mistake_en": "Holding bank until exactly the target heading, then overshooting.", "sources": ["BOOK", "FAA"]}], "quiz": [["Ce componentă a liftului schimbă direcția într-un viraj banked?", "Which lift component changes direction in a banked turn?", ["Componenta orizontală", "Doar componenta verticală", "Weight", "Drag zero"], 0, "Bank-ul înclină vectorul de lift și creează o componentă orizontală.", "Bank tilts the lift vector and creates a horizontal component."], ["Pentru a menține altitudinea într-un level turn, total lift trebuie de regulă să…", "To maintain altitude in a level turn, total lift generally must…", ["crească", "scadă la zero", "rămână identic indiferent de bank", "dispară"], 0, "Componenta verticală trebuie să continue să echilibreze weight.", "The vertical component must continue to balance weight."], ["Mai mult bank într-un level turn înseamnă de regulă…", "More bank in a level turn generally means…", ["load factor mai mare", "load factor zero", "stall speed mai mică garantat", "fără schimbare"], 0, "Load factor crește cu bank-ul într-un viraj nivelat.", "Load factor increases with bank in a level turn."], ["Când load factor crește, stall speed…", "When load factor increases, stall speed…", ["crește", "scade la zero", "nu poate fi afectată", "devine groundspeed"], 0, "Stall speed crește pe măsură ce load factor-ul crește.", "Stall speed increases as load factor increases."], ["Rudder-ul într-un viraj normal…", "In a normal turn, the rudder…", ["coordonează yaw-ul", "înlocuiește bank-ul", "controlează direct altitudinea", "este inutil"], 0, "Rudder-ul ajută la coordonare, în timp ce bank-ul creează componenta de viraj.", "The rudder helps coordination while bank creates the turning component."], ["Roll-out-ul pentru un heading selectat începe de regulă…", "Roll-out for a selected heading generally begins…", ["înainte de heading", "după un overshoot mare", "exact la heading indiferent de rate", "doar după reducerea puterii"], 0, "Este necesară anticipare pentru a evita overshoot-ul.", "Anticipation is required to avoid overshoot."]]},
{"id": 10, "title_ro": "Slow Flight & Stalling", "title_en": "Slow Flight & Stalling", "time": "70 min", "pages": "Pooley Vol. 1 • Exercises 10a–10b • printed pp. 167–186", "summary_ro": "Capitol critic: cum se schimbă avionul la viteză mică, de ce stall-ul este legat de critical angle of attack și de ce recuperarea începe prin reducerea AOA.", "summary_en": "Critical chapter: how the aeroplane changes at low airspeed, why a stall is tied to critical angle of attack, and why recovery begins by reducing AOA.", "objectives_ro": ["recunoști caracteristicile slow flight", "înțelegi relația dintre AOA, lift și drag", "recunoști semnele apropierii de stall", "înțelegi principiul general al recuperării și limitele aircraft-specific"], "objectives_en": ["recognise slow-flight characteristics", "understand the relationship between AOA, lift, and drag", "recognise signs of an approaching stall", "understand the general recovery principle and aircraft-specific limits"], "sections": [{"title_ro": "Slow flight este o stare de energie", "title_en": "Slow flight is an energy state", "body_ro": "La viteză mică, avionul trebuie de regulă să opereze la un AOA mai mare pentru a produce lift-ul necesar. Induced drag crește, control effectiveness poate scădea, iar managementul puterii devine mai important.", "body_en": "At low airspeed, the aeroplane generally needs a higher AOA to produce the required lift. Induced drag increases, control effectiveness can decrease, and power management becomes more important.", "cockpit_ro": "Așteaptă-te la comenzi mai «moi», pitch mai ridicat și nevoia de corecții deliberate, dar fine.", "cockpit_en": "Expect softer controls, a higher pitch attitude, and the need for deliberate but smooth corrections.", "mistake_ro": "Input-uri brute când marja energetică este mică.", "mistake_en": "Abrupt inputs when the energy margin is small.", "sources": ["BOOK", "FAA"]}, {"title_ro": "Partea din spate a power curve", "title_en": "The back side of the power curve", "body_ro": "În regimul de viteză foarte mică, o reducere suplimentară a vitezei poate necesita mai multă putere pentru a menține altitudinea, deoarece induced drag crește puternic. «Mai încet» nu înseamnă automat «mai puțină putere».", "body_en": "In the very-low-speed regime, a further reduction in airspeed may require more power to maintain altitude because induced drag rises strongly. “Slower” does not automatically mean “less power.”", "cockpit_ro": "Observă relația dintre pitch, power și rate of climb/descent, nu doar cifra de pe ASI.", "cockpit_en": "Observe the relationship between pitch, power, and rate of climb/descent, not just the ASI number.", "mistake_ro": "A reduce viteza fără a anticipa creșterea drag-ului.", "mistake_en": "Reducing speed without anticipating the increase in drag.", "sources": ["BOOK", "FAA"]}, {"title_ro": "Stall-ul apare la critical AOA", "title_en": "The stall occurs at critical AOA", "body_ro": "Un stall apare când aripa depășește critical angle of attack și airflow-ul nu mai poate menține distribuția de presiune necesară pentru lift-ul normal. Acest lucru se poate întâmpla la viteze diferite, în funcție de load factor, configurație și manevră.", "body_en": "A stall occurs when the wing exceeds the critical angle of attack and the airflow can no longer maintain the pressure distribution required for normal lift. This can happen at different airspeeds depending on load factor, configuration, and manoeuvre.", "cockpit_ro": "Modelul corect: stall nu este o «viteză magică»; stall înseamnă critical AOA exceeded.", "cockpit_en": "Correct model: a stall is not a “magic speed”; a stall means critical AOA exceeded.", "mistake_ro": "A crede că peste viteza publicată de stall avionul nu poate stalla.", "mistake_en": "Believing the aeroplane cannot stall above the published stall speed.", "sources": ["BOOK", "FAA"]}, {"title_ro": "Semnele apropierii de stall", "title_en": "Signs of an approaching stall", "body_ro": "Semnele pot include control effectiveness redusă, schimbarea sunetului airflow-ului, buffet, stall warning și o stare de energie caracteristică. Indiciile exacte diferă între aeronave și configurații.", "body_en": "Signs can include reduced control effectiveness, a change in airflow sound, buffet, stall warning, and a characteristic energy state. Exact cues differ between aircraft and configurations.", "cockpit_ro": "Învață să recunoști mai multe indicii, nu să aștepți un singur warning.", "cockpit_en": "Learn to recognise multiple cues rather than waiting for one warning.", "mistake_ro": "Dependența totală de stall horn.", "mistake_en": "Complete dependence on the stall horn.", "sources": ["BOOK", "FAA", "AFM"]}, {"title_ro": "Principiul recuperării: redu AOA", "title_en": "Recovery principle: reduce AOA", "body_ro": "Acțiunea aerodinamică esențială pentru ieșirea din stall este reducerea angle of attack sub valoarea critică. Apoi pilotul gestionează puterea, bank-ul, configurația și revenirea la traiectoria dorită conform procedurii aeronavei și instruirii.", "body_en": "The essential aerodynamic action for leaving a stall is reducing angle of attack below the critical value. The pilot then manages power, bank, configuration, and return to the desired flight path according to aircraft procedure and training.", "cockpit_ro": "AOA first. Secvența exactă și prioritățile detaliate trebuie predate și practicate cu instructorul pe avionul respectiv.", "cockpit_en": "AOA first. The exact sequence and detailed priorities must be taught and practised with an instructor on the specific aircraft.", "mistake_ro": "A trage de manșă pentru a opri sink-ul înainte ca aripa să fie unstalled.", "mistake_en": "Pulling back to stop the sink before the wing has been unstalled.", "sources": ["BOOK", "FAA", "EASA", "AFM"]}, {"title_ro": "Load factor și accelerated stall", "title_en": "Load factor and accelerated stall", "body_ro": "Un avion poate stalla la o viteză mai mare decât viteza 1G publicată dacă load factor-ul este mai mare. Un level turn cu bank mai mare cere mai mult lift și crește load factor-ul, reducând stall margin.", "body_en": "An aeroplane can stall at an airspeed higher than the published 1G stall speed when load factor is higher. A steeper level turn requires more lift and increases load factor, reducing stall margin.", "cockpit_ro": "La low altitude, combinația low speed + bank + necoordonare este o amenințare majoră.", "cockpit_en": "At low altitude, the combination of low airspeed + bank + uncoordination is a major threat.", "mistake_ro": "A considera că numai zborul drept și foarte lent poate duce la stall.", "mistake_en": "Assuming only straight, very slow flight can lead to a stall.", "sources": ["BOOK", "FAA", "EASA"]}, {"title_ro": "Slow flight cere lookout și finețe", "title_en": "Slow flight requires lookout and finesse", "body_ro": "Atitudinea cu nasul ridicat poate ascunde trafic, iar avionul răspunde mai lent. Lookout-ul, coordonarea și managementul energiei trebuie menținute în timp ce practici viraje, urcări și coborâri la viteză mică.", "body_en": "The higher nose attitude can hide traffic and the aeroplane responds more slowly. Lookout, coordination, and energy management must be maintained while practising turns, climbs, and descents at low airspeed.", "cockpit_ro": "Nu lăsa concentrarea pe ASI să elimine exteriorul din scan.", "cockpit_en": "Do not let concentration on the ASI remove the outside world from the scan.", "mistake_ro": "Fixation pe airspeed în timp ce bank-ul, heading-ul sau altitudinea se degradează.", "mistake_en": "Fixating on airspeed while bank, heading, or altitude deteriorate.", "sources": ["BOOK", "FAA"]}], "quiz": [["Stall-ul apare când…", "A stall occurs when…", ["viteza este sub o singură valoare universală", "critical angle of attack este depășit", "motorul este la idle", "flaps sunt sus"], 1, "Cauza aerodinamică este depășirea AOA critic.", "The aerodynamic cause is exceeding critical AOA."], ["Poate un avion stalla peste viteza de stall publicată pentru 1G?", "Can an aeroplane stall above the published 1G stall speed?", ["Da, dacă load factor este mai mare", "Nu, niciodată", "Doar pe sol", "Doar cu motor oprit"], 0, "Load factor mai mare crește stall speed.", "Higher load factor increases stall speed."], ["Acțiunea aerodinamică esențială pentru recuperare este…", "The essential aerodynamic action for recovery is…", ["reducerea AOA", "tragerea maximă de manșă", "ignorarea warning-ului", "bank mai mare"], 0, "Aripa trebuie adusă sub critical AOA.", "The wing must be brought below critical AOA."], ["La slow flight, control effectiveness este adesea…", "In slow flight, control effectiveness is often…", ["redusă", "infinită", "independentă de airflow", "mai mare garantat"], 0, "Airflow mai mic poate reduce eficiența comenzilor.", "Lower airflow can reduce control effectiveness."], ["Pe partea din spate a power curve, o viteză și mai mică poate cere…", "On the back side of the power curve, an even lower airspeed may require…", ["mai multă putere pentru a menține altitudinea", "zero putere întotdeauna", "frâne", "doar rudder"], 0, "Induced drag crește puternic la viteze foarte mici.", "Induced drag rises strongly at very low airspeeds."], ["De ce nu te bazezi exclusiv pe stall horn?", "Why not rely exclusively on the stall horn?", ["Semnele și sistemele diferă, iar awareness-ul folosește mai multe indicii", "Pentru că nu există pe niciun avion", "Pentru că doar instructorul îl aude", "Pentru că indică GPS speed"], 0, "Recunoașterea folosește un set de indicii, nu un singur warning.", "Recognition uses a set of cues, not a single warning."], ["Într-un level turn mai abrupt, stall margin la aceeași IAS tinde să…", "In a steeper level turn, stall margin at the same IAS tends to…", ["scadă", "crească infinit", "rămână garantat identică", "nu aibă legătură cu load factor"], 0, "Bank-ul mai mare crește load factor și stall speed.", "More bank increases load factor and stall speed."], ["În slow flight, pilotul trebuie să…", "In slow flight, the pilot must…", ["mențină lookout și coordonare", "privească doar ASI", "facă input-uri brute", "ignore bank-ul"], 0, "Slow flight este un exercițiu de awareness și control, nu de fixation.", "Slow flight is an awareness and control exercise, not fixation."]]}
]};
